#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;

int n,m,f[N];
long long a[N],t[N<<2];

int father(int x){
    return f[x]==x?x:f[x]=father(f[x]);
}

void build(int cur,int l,int r){
    if(l==r){
        t[cur]=a[l];
        return;
    }
    int mid=l+r>>1;
    build(cur*2,l,mid);
    build(cur*2+1,mid+1,r);
    t[cur]=t[cur*2]+t[cur*2+1];
}

long long query(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[cur];
    int mid=l+r>>1;
    long long res=0;
    if(x<=mid)
        res+=query(cur*2,l,mid,x,y);
    if(y>mid)
        res+=query(cur*2+1,mid+1,r,x,y);
    return res;
}

void modify(int cur,int l,int r,int x){
    if(l==r){
        t[cur]=sqrt(t[cur]);
        return;
    }
    int mid=l+r>>1;
    if(x<=mid)
        modify(cur*2,l,mid,x);
    else
        modify(cur*2+1,mid+1,r,x);
    t[cur]=t[cur*2]+t[cur*2+1];
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%lld",&a[i]);
        f[i]=i;
    }
    f[n+1]=n+1;
    build(1,1,n);
    scanf("%d",&m);
    while(m--){
        int op,l,r;
        scanf("%d%d%d",&op,&l,&r);
        if(l>r) swap(l,r);
        if(op)
            printf("%lld\n",query(1,1,n,l,r));
        else{
            int p=father(l);
            while(p<=r){
                modify(1,1,n,p);
                a[p]=sqrt(a[p]);
                if(a[p]==1)
                    f[p]=father(p+1);
                p=father(p+1);
            }
        }
    }
    return 0;
}
